	private void addProductionLine(ModelBuilder builder, IRI environment, String lineId, int lineIndex,
			List<String> driveUnitIds, List<String> sensorIds) {
		String aasId = "urn:aas:ProductionLineAAS:" + lineId;
		String submodelId = "urn:submodel:ProductionLine:Overview:" + lineId;

		IRI aas = iri(aasId);
		IRI submodel = iri(submodelId);
		IRI assetInfo = genId();

		builder.subject(environment)
				.add(ns1("assetAdministrationShell"), aas)
				.add(ns1("submodel"), submodel);

		var ref = createReference(builder, submodel, KEY_TYPE_SUBMODEL, 0);
		builder.subject(aas)
				.add(RDF.TYPE, ASSET_ADMINISTRATION_SHELL)
				.add(ns1("id"), aasId)
				.add(ns1("idShort"), "ProdLineAAS_" + lineId.replace('-', '_'))
				.add(ns1("modelVersion"), "3.1")
				.add(ns1("assetInformation"), assetInfo)
				.add(ns1("submodel"), submodel)
				.add(ns1("submodelReference"), ref);

		builder.subject(assetInfo)
				.add(RDF.TYPE, ASSET_INFORMATION)
				.add(ns1("assetKind"), ASSET_KIND_INSTANCE)
				.add(ns1("globalAssetId"), "urn:asset:ProductionLine:" + lineId);

		IRI lineName = iri(submodelId + "/lineName");
		IRI lineStatus = iri(submodelId + "/lineStatus");
		List<IRI> elements = new ArrayList<>();
		elements.add(lineName);
		elements.add(lineStatus);

		builder.subject(submodel)
				.add(RDF.TYPE, SUBMODEL)
				.add(ns1("assetAdministrationShell"), aas)
				.add(ns1("category"), "OPERATION")
				.add(ns1("id"), submodelId)
				.add(ns1("idShort"), "LineOverview")
				.add(ns1("modelVersion"), "3.1")
				.add(ns1("modelingKind"), MODELLING_KIND_INSTANCE);

		builder.subject(lineName)
				.add(RDF.TYPE, PROPERTY)
				.add(ns1("idShort"), "lineName")
				.add(ns1("index"), 0)
				.add(ns1("value"), "Assembly Line " + lineIndex)
				.add(ns1("valueType"), XSD.STRING);

		builder.subject(lineStatus)
				.add(RDF.TYPE, PROPERTY)
				.add(ns1("idShort"), "lineStatus")
				.add(ns1("index"), 1)
				.add(ns1("value"), "RUNNING")
				.add(ns1("valueType"), XSD.STRING);

		int relationshipIndex = 2;
		for (String driveUnitId : driveUnitIds) {
			elements.add(addRelationship(builder, lineId, submodelId, driveUnitId, relationshipIndex++));
		}
		for (String sensorId : sensorIds) {
			elements.add(addRelationship(builder, lineId, submodelId, sensorId, relationshipIndex++));
		}

		for (IRI element : elements) {
			builder.subject(submodel).add(ns1("submodelElement"), element);
		}
	}

	private IRI addRelationship(ModelBuilder builder, String lineId, String productionSubmodelId, String componentId,
			int index) {
		boolean driveUnit = componentId.startsWith("DU-");
		String relationIri = productionSubmodelId + "/consistsOf_" + componentId.replace('-', '_');
		String componentAas = driveUnit ? "urn:aas:DriveUnitAAS:" : "urn:aas:SensorAAS:";

		IRI relation = iri(relationIri);
		IRI firstRef = createReference(builder, iri("urn:aas:ProductionLineAAS:" + lineId), KEY_TYPE_AAS, null);
		IRI secondRef = createReference(builder, iri(componentAas + componentId), KEY_TYPE_AAS, null);
		IRI semanticId = createReference(builder, iri(CONCEPT_LINE_CONSISTS), KEY_TYPE_CONCEPT_DESCRIPTION, null);

		builder.subject(relation)
				.add(RDF.TYPE, RELATIONSHIP_ELEMENT)
				.add(ns1("idShort"), "consistsOf_" + componentId.replace('-', '_'))
				.add(ns1("index"), index)
				.add(ns1("conceptDescription"), iri(CONCEPT_LINE_CONSISTS))
				.add(ns1("first"), firstRef)
				.add(ns1("second"), secondRef)
				.add(ns1("semanticId"), semanticId);

		return relation;
	}

	private IRI addSpecificAssetId(ModelBuilder builder, int index, String name, String value) {
		IRI id = genId();
		builder.subject(id)
				.add(RDF.TYPE, SPECIFIC_ASSET_ID)
				.add(ns1("index"), index)
				.add(ns1("name"), name)
				.add(ns1("value"), value);
		return id;
	}

	private IRI createReference(ModelBuilder builder, IRI target, IRI keyType, Integer keyIndex) {
		IRI reference = genId();
		IRI key = genId();
		builder.subject(reference)
				.add(RDF.TYPE, REFERENCE)
				.add(RESOLVES_TO, target)
				.add(ns1("key"), key)
				.add(ns1("referenceType"), REFERENCE_TYPE_MODEL_REFERENCE);
		if (keyIndex != null) {
			builder.subject(reference).add(ns1("index"), keyIndex);
		}

		builder.subject(key)
				.add(RDF.TYPE, KEY)
				.add(ns1("index"), 0)
				.add(ns1("keyType"), keyType)
				.add(ns1("value"), target.stringValue());
		return reference;
	}

	private static IRI ns1(String localName) {
		return VF.createIRI(NS1, localName);
	}

	private static IRI ns2(String localName) {
		return VF.createIRI(NS2, localName);
	}

	private static IRI iri(String iri) {
		return VF.createIRI(iri);
	}

	private static IRI genId() {
		return iri("https://company.com/.well-known/genid/aas/N" + UUID.randomUUID().toString().replace("-", ""));
	}

	private static double randomDouble(double min, double max) {
		return ThreadLocalRandom.current().nextDouble(min, max);
	}

	private static int randomInt(int minInclusive, int maxExclusive) {
		return ThreadLocalRandom.current().nextInt(minInclusive, maxExclusive);
	}
